#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,a[10501];
    double num1=0,num2=0;
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        num1+=(a[i]*x);
    }for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        num2+=(a[i]*x);
    }
    if(num1>num2){
        cout<<"ke";
    }else if(num1<num2){
        cout<<"do";
    }else{
        cout<<"same";
    }
    return 0;
}
